window.onload = init;
// Goal Counter
var kickCount = 1;
var count = 0;
var goalCounter = document.getElementById('goal_counter');
var goalCounterBalls = document.getElementById('goal_counter_balls')
// Get the element ID from the document page
var ball = document.getElementById('ball')
var shootLeftBtn = document.getElementById('shoot_left'); // Shoot left button
var shootCenterBtn = document.getElementById('shoot_center'); // shoot right button 
var shootRightBtn = document.getElementById('shoot_right'); // shoot right button 
// Keeper Wrapper
// var keeper_wrapper = document.getElementById('keeper_wrapper')
var keeperStand = document.getElementById('stand');
// Keeper Objects
var keeper = [
    document.getElementById('left'),
    document.getElementById('center'),
    document.getElementById('right')
];

// Audio and sound elements
/**
 * 
 */
var ballKick = document.getElementById('ballKick');
var stadiumNoise = document.getElementById('stadiumNoise');
var keeperJumpSound = document.getElementById('keeperJumpSound')
// Goal and not Goal message
var goalMessage = document.getElementById('goal_message');
var missGoalMessage = document.getElementById('miss_goal_message');
/**
 * Initialize the page with the goal counter and the keeper's position
*/
function init() {
    stadiumNoise.play();
    stadiumNoise.volume = .1;

    // Initialize the goal counter
    // var goalCounter = document.getElementById('goal_counter');
    goalCounter.innerHTML = count; // Set the initial goal counter to 0
    /**
     * Add event listeners to the shoot buttons to trigger the corresponding shoot functions when clicked
     */
    // var shootLeftBtn = document.getElementById('shoot_left'); // Shoot left button
    shootLeftBtn.addEventListener('click', shootLeft);
    // var shootCenterBtn = document.getElementById('shoot_center'); // shoot right button 
    shootCenterBtn.addEventListener('click', shootCenter);
    // var shootRightBtn = document.getElementById('shoot_right'); // shoot right button    
    shootRightBtn.addEventListener('click', shootRight);

}
// Function to handle the keeper's actions based on the random jump and the direction of the shot
// This function takes in the random jump index and the direction of the shot, and updates the keeper's animation and the goal counter accordingly
// It also updates the goal counter balls to show whether the shot was a goal or a miss
// The function uses the random jump index to determine which keeper image to animate, and compares the jump direction with the shot direction to determine if it was a goal or a miss
// If it was a goal, it increments the goal counter and updates the goal counter balls with a green ball image. If it was a miss, it updates the goal counter balls with a red ball image.
function keeperActions(randomJump, direction) {
    // ballKick.muted = false; // Unmute the ball kick sound effect to ensure it plays when the keeper actions function is called
    // ballKick.loop = false; // default, but explicit
    // Play the ball kick sound effect when the keeper actions function is called
    ballKick.play();
    // Increment the kick count each time the keeper actions function is called to keep track of the number of shots taken
    kickCount++; // Increment the kick count each time the keeper actions function is called
    // Check if the kick count has reached 10 to determine if the game is over and needs to be reset
    // If the kick count is 10, show an alert message to the user indicating that the game is over and then reload the page after a short delay to reset the game
    /**
     * Check if the kick count has reached 10 to determine if the game is over and needs to be reset. If the kick count is 10, show an alert message to the user indicating that the game is over and then reload the page after a short delay to reset the game.
     */
    keeperJumpSound.play(); //
    keeperJumpSound.volume = 0.1; //
    if (kickCount === 10) {
        ballKick.pause();
        setTimeout(() => {
            alert(`Game Over! Your score is ${count}`); // Show an alert message to the user indicating that the game is over after 10 kicks
            window.location.reload(); // Reload the page after a short delay to reset the game after 10 kicks
        }, 2000);
        // Reload the page if the goal count is between 1 and 9 to reset the game
        // Pause the ball kick sound effect after a short delay to ensure it does not continue playing indefinitely
        // window.location.reload(); // Reload the page to reset the game if the goal count is between 1 and 9
    }
    /**
     * Hide the standing keeper image and show the randomly selected keeper image based on the random jump index to create the animation effect of the keeper jumping in a specific direction. The function first hides the standing keeper image by adding the "hide" class to it, then it loops through all keeper images and hides them by adding the "hide" class to them, except for the randomly selected keeper image which will be shown by removing the "hide" class from it. This allows for the animation of the randomly selected keeper image while keeping the others hidden.
     */
    keeperStand.classList.add("hide"); // Hide the standing keeper image
    // Get the ID of the randomly selected keeper image based on the random jump index to determine which keeper image will be animated when the player takes a shot
    const jump = keeper[randomJump].id;
    /* Loop through all keeper images and hide them by adding the "hide" class to them, except for the randomly selected keeper image which will be shown by removing the "hide" class from it. This allows for the animation of the randomly selected keeper image while keeping the others hidden.
        */
    keeper.forEach(element => {
        if (element.id !== jump) {
            element.classList.add("hide"); // Hide all other keeper images by adding the "hide" class to them
        } else {
            element.classList.remove("hide"); // Show the randomly selected keeper image by removing the "hide" class from it
        }
    });

    // Check if the jump direction is different from the shot direction to determine if it was a goal or a miss
    if (jump !== direction) {
        count = count + 1 // Increment the goal count if it was a goal
        //  
        goalCounter.innerHTML = count; // Set the initial goal counter to 0
        goalMessage.classList.remove("hide"); // Show the goal message by removing the "hide" class from it
        goalMessage.classList.add("fade-in"); // Add the fade-in animation class to the goal message
        missGoalMessage.classList.add("hide"); // Hide the miss goal message by adding the "hide" class to it // Update the goal counter display with the new goal count
        goalCounterBalls.innerHTML += `<li>
        <img src="./assets/img/green-ball.png" height="30px">
        </li>`

    } else {
        missGoalMessage.classList.remove("hide"); // Show the miss goal message by removing the "hide" class from it
        missGoalMessage.classList.add("fade-in"); // Add the fade-in animation class to the miss goal message
        goalMessage.classList.add("hide"); // Show the miss goal message by removing the "hide" class from it
        goalCounterBalls.innerHTML += `<li>
        <img src="./assets/img/red-ball.png" height="30px">
        </li>`
    }

    // Reset the keeper's position and the ball animation after a short delay to allow the animations to play out
    setTimeout(() => {
        keeper.forEach(element => {
            element.classList.add("hide"); // Hide all keeper images by adding the "hide" class to them
        });
        keeperStand.classList.remove("hide"); // Show the standing keeper image by removing the "hide" class from it
        ball.className = ""; // Reset the ball's class to stop any ongoing animations
    }, 1000);

}
// Functions for the buttons
// Each function generates a random jump for the keeper, calls the keeperActions function with the random jump and the corresponding direction of the shot, and then adds the appropriate animation class to the ball element to trigger the shooting animation in the correct direction
function shootLeft() {
    const random = RandomJumpFun()
    keeperActions(random, "left")
    ball.className = "";
    ball.classList.add("ball_left_animation");
}
// Each function generates a random jump for the keeper, calls the keeperActions function with the random jump and the corresponding direction of the shot, and then adds the appropriate animation class to the ball element to trigger the shooting animation in the correct direction
function shootRight() {
    const random = RandomJumpFun()
    keeperActions(random, "right")
    ball.className = "";
    ball.classList.add("ball_right_animation");
}
// Each function generates a random jump for the keeper, calls the keeperActions function with the random jump and the corresponding direction of the shot, and then adds the appropriate animation class to the ball element to trigger the shooting animation in the correct direction
function shootCenter() {
    const random = RandomJumpFun()
    keeperActions(random, "center")
    ball.className = "";
    ball.classList.add("ball_center_animation");
}
// Function to generate a random jump for the keeper by generating a random number between 0 and 2 (inclusive) which corresponds to the index of the keeper images in the keeper array. This function is used to determine which keeper image will be animated when the player takes a shot.
function RandomJumpFun() {
    const randomAction = Math.floor(Math.random() * 3);
    return randomAction
}